use clap::Parser;

#[derive(Parser)]
#[command(
    version = env!("CARGO_PKG_VERSION"),
    about = "My Tool",
    long_about = None,
)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

// For detailed version info:
fn version_info() -> String {
    format!(
        "{} v{}\nBuilt with Rust {}\nTarget: {}",
        env!("CARGO_PKG_NAME"),
        env!("CARGO_PKG_VERSION"),
        env!("CARGO_PKG_RUST_VERSION"),
        env!("TARGET"),  // Set via build script
    )
}
